CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `view_usuarios`  AS   (select distinct `g`.`id` AS `id`,`g`.`nick` AS `nick`,`g`.`email` AS `email`,`g`.`password` AS `password` from (`guerreros` `g` join `guerreros_roles` `gr` on((`g`.`id` = `gr`.`guerrero_id`))) order by `g`.`nick`)  ;

